// Config holds all configuration parameters for the SDK client.
// It manages base URL, timeout, authentication credentials, and custom hooks.
type Config struct {
	BaseUrl     *string
	Timeout     *time.Duration
	AccessToken *string
	HookParams  map[string]string
	hook        hooks.Hook
}

// NewConfig creates a new Config instance with default values.
// Sets the base URL to the default environment and timeout to 10 seconds.
func NewConfig() Config {
	baseUrl := DEFAULT_ENVIRONMENT
	timeout := time.Second * 10
	newConfig := Config{
		BaseUrl:    &baseUrl,
		Timeout:    &timeout,
		HookParams: make(map[string]string),
	}

	return newConfig
}

func (c *Config) SetBaseUrl(baseUrl string) {
	c.BaseUrl = &baseUrl
}

func (c *Config) GetBaseUrl() string {
	return *c.BaseUrl
}

func (c *Config) SetTimeout(timeout time.Duration) {
	c.Timeout = &timeout
}

func (c *Config) GetTimeout() time.Duration {
	return *c.Timeout
}

func (c *Config) SetAccessToken(accessToken string) {
	c.AccessToken = &accessToken
}

func (c *Config) GetAccessToken() string {
	return *c.AccessToken
}

package client

import (
	"github.com/magicbell/magicbell-go/pkg/user-client/internal/clients/rest/hooks"
	"github.com/magicbell/magicbell-go/pkg/user-client/internal/configmanager"
	"github.com/magicbell/magicbell-go/pkg/user-client/channels"
	"github.com/magicbell/magicbell-go/pkg/user-client/clientconfig"
	"github.com/magicbell/magicbell-go/pkg/user-client/integrations"
	"github.com/magicbell/magicbell-go/pkg/user-client/notifications"
	"time"
)

// Client is the main SDK client that provides access to all service endpoints.
// It manages configuration, authentication, and service instances with centralized settings.
type Client struct {
	Channels      *channels.ChannelsService
	Integrations  *integrations.IntegrationsService
	Notifications *notifications.NotificationsService
	manager       *configmanager.ConfigManager
}

func NewClient(config clientconfig.Config) *Client {
	channels := channels.NewChannelsService()
	integrations := integrations.NewIntegrationsService()
	notifications := notifications.NewNotificationsService()

	manager := configmanager.NewConfigManager(config)
	hook := hooks.NewDefaultHook()
	channels.WithConfigManager(manager)
	integrations.WithConfigManager(manager)
	notifications.WithConfigManager(manager)
	channels.WithHook(hook)
	integrations.WithHook(hook)
	notifications.WithHook(hook)

	return &Client{
		Channels:      channels,
		Integrations:  integrations,
		Notifications: notifications,
		manager:       manager,
	}
}

func (c *Client) SetBaseUrl(baseUrl string) {
	c.manager.SetBaseUrl(baseUrl)
}

func (c *Client) SetTimeout(timeout time.Duration) {
	c.manager.SetTimeout(timeout)
}

func (c *Client) SetAccessToken(accessToken string) {
	c.manager.SetAccessToken(accessToken)
}

